from flask import Flask, jsonify

app = Flask(__name__)

@app.route('/')
def home():
    return 'Hello from Flask'

@app.route('/health')
def health():
    return jsonify({'status': 'ok'})

if __name__ == '__main__':
    print("Flask server starting on port 5000")
    app.run(host='0.0.0.0', port=5000, debug=False)
